def _ok(result):
    return json.dumps({"success": True, "data": result}, indent=2)

def _err(message):
    return json.dumps({"success": False, "error": message}, indent=2)


TOOL_NAME = "agent_observability_cost_calculator"
TOOLSET = "agents"

SCHEMA = {
  "type": "function",
  "function": {
    "name": "agent_observability_cost_calculator",
    "description": "Estimate monthly observability cost for LLM agents across providers.",
    "parameters": {
      "type": "object",
      "properties": {
        "monthly_requests": {
          "type": "integer",
          "description": "Monthly LLM requests."
        },
        "traces_per_request": {
          "type": "integer",
          "description": "Spans per request."
        },
        "team_size": {
          "type": "integer",
          "description": "Team members needing seats."
        },
        "sampling_pct": {
          "type": "number",
          "description": "Trace sampling percentage."
        }
      },
      "required": []
    }
  }
}

def _run(args):
    monthly_requests = int(args.get("monthly_requests", DATA["defaults"]["monthly_requests"]))
    traces_per_request = int(args.get("traces_per_request", DATA["defaults"]["traces_per_request"]))
    team_size = int(args.get("team_size", DATA["defaults"]["team_size"]))
    sampling_pct = float(args.get("sampling_pct", DATA["defaults"]["sampling_pct"]))
    observations = int(monthly_requests * traces_per_request * (sampling_pct / 100))
    results = []
    for provider in DATA["providers"]:
        cost = 0
        free_tier = provider.get("free_tier", {})
        included = free_tier.get("events", 0)
        billable = max(0, observations - included)
        per_event = provider.get("cost_per_1m_events", 0)
        cost += billable * per_event / 1_000_000
        seat_cost = provider.get("cost_per_seat", 0) * team_size
        cost += seat_cost
        results.append({
            "provider": provider.get("name"),
            "estimated_monthly_cost": round(cost, 2),
            "billable_observations": billable,
            "free_tier_included": included,
        })
    results.sort(key=lambda x: x["estimated_monthly_cost"])
    return _ok({"observations": observations, "providers": results[:5]})

def HANDLER(args):
    try:
        return _run(args)
    except Exception as e:
        return _err(str(e))


def register():
    """Manual registry hook. Import and call this to register with Hermes."""
    try:
        from tools.registry import registry
        registry.register(
            name=TOOL_NAME,
            toolset=TOOLSET,
            schema=SCHEMA,
            handler=HANDLER,
        )
    except ImportError:
        print("Hermes registry not found; skipping manual registration.")

